def make_single_assembler(recipe="stack-inserter",dx=0,dy=0):
	# print(f"def make_single_assembler(recipe={recipe}, dx={dx}, dy = {dy}")
	blueprint_copy = copy.deepcopy(blueprint)
	for i,v in enumerate(blueprint["blueprint"]["entities"]):
		# print(f"name {v["name"]}")
		v_copy = copy.deepcopy(v)
		v_copy["position"]["x"]+=dx
		v_copy["position"]["y"]+=dy

		if v["name"] == "logistic-chest-requester":
			v_copy["request_filters"] = make_request_filters(recipe)

		elif "inserter" in v["name"]:
			v_copy["name"] = "fast-inserter"
		elif "assembling-machine" in v["name"]:

			v_copy["name"] = "assembling-machine-3"
			v_copy["recipe"] = recipe
			v_copy["items"] = {"speed-module-3": 4}
			if is_smelted(v["recipe"]) or "plate" in recipe or "stone" in recipe:
				v_copy["name"] = "electric-furnace"
		blueprint_copy["blueprint"]["entities"][i] = v_copy
	return blueprint_copy

def re_index(blueprint):
	for i,v in enumerate(blueprint["blueprint"]["entities"]):
		blueprint["blueprint"]["entities"][i]["entity_number"]=i+1

def get_x_and_y_distance(blueprint):
	roboport_x,roboport_y = 0,0
	mininum_x,maximum_x = [blueprint["blueprint"]["entities"][0]["position"]["x"]]*2
	mininum_y,maximum_y = [blueprint["blueprint"]["entities"][0]["position"]["y"]]*2
	for i,v in enumerate(blueprint["blueprint"]["entities"]):
		# if v["name"] == "roboport":

		x,y = v["position"].values()
		if x < mininum_x:
			mininum_x = x
		if x > maximum_x:
			maximum_x = x 
		if y < mininum_y:
			mininum_y = y
		if y > maximum_y:
			maximum_y = y
	return [maximum_x - mininum_x,maximum_y - mininum_y]

def merge_blueprint(original,new):

	for i in new["blueprint"]["entities"]:
		original["blueprint"]["entities"].append(copy.deepcopy(i))


def make_row_of_assemblers(list_of_recipes,delta_x=0,delta_y=0):
	original = make_single_assembler(list_of_recipes[0])

	dx = 0
	for index, recipe in enumerate(list_of_recipes):
		# print("delta_y in for loop of make_row_of_assemblers = ",delta_y)
		new_blueprint = make_single_assembler(recipe,dx,delta_y)
		if index == len(list_of_recipes) -1:
			for i,v in enumerate(new_blueprint["blueprint"]["entities"]):
				if "electric-pole" in v["name"] or "substation" in v["name"]:
					v["end_pole"] = True 
					new_blueprint["blueprint"]["entities"][i]=v

		new_dx,_ = copy.deepcopy(get_x_and_y_distance(new_blueprint))
		dx += 3
		merge_blueprint(original,new_blueprint)
		

	return original

 
#this a

def make_roughly_square_array_of_assemblers(list_of_recipes):
	original = make_single_assembler()
	original["blueprint"]["entities"] = []
	collength = int(numpy.sqrt((len(list_of_recipes))))

	## this basically makes as close to a square array as possible
	k, m = divmod(len(list_of_recipes), collength)
	list_of_recipes =  [list_of_recipes[i*k+min(i, m):(i+1)*k+min(i+1, m)] for i in range(collength)]
	print([len(i) for i in list_of_recipes])
	print(sum([len(i) for i in list_of_recipes]))
	change_in_y = 0 
	for recipe_slice in list_of_recipes:
		# print("change_in_y",change_in_y)
		row = make_row_of_assemblers(recipe_slice,0,change_in_y)
		merge_blueprint(original,row)
		_, new_dy = get_x_and_y_distance(row)
		change_in_y += 5
	re_index(original)
	return original




def electrify(blueprint):
	endpole_indices = []
	pole, prev_pole = False, False
	for i,v in  enumerate(blueprint["blueprint"]["entities"]):
		if "electric-pole" in v["name"] or "substation" == v["name"]:
			if "end_pole" in v:
				endpole_indices.append(i)
			pole = copy.deepcopy(v)
			if prev_pole: # then prev_pole must exist
				if "neighbours" in v:
					blueprint["blueprint"]["entities"][i]["neighbours"] += [prev_pole["entity_number"]] 

				else:
					blueprint["blueprint"]["entities"][i]["neighbours"] = [prev_pole["entity_number"]] 
				## this tells you that you've reached the end because when you're adding one row to the next the first pole of the next
				## row will be way down on the other end, so you don't connect it to the next row until you've gotten down to the end of the
				## next row where again, you'll have the same problem of connecting up to the next row, i.e. like the same issue with trying
				## to finish this sentence.
	
			if pole:
				prev_pole = copy.deepcopy(pole)

	print(endpole_indices,"endpole_indices")
	pole, prev_pole = False, False
	for i in  range(1,len(endpole_indices)):
		index_pole_1,index_pole_2 = endpole_indices[i],endpole_indices[i-1]
		blueprint["blueprint"]["entities"][index_pole_2]["neighbours"] += [blueprint["blueprint"]["entities"][index_pole_1]["entity_number"]] 
		blueprint["blueprint"]["entities"][index_pole_1]["neighbours"] += [blueprint["blueprint"]["entities"][index_pole_2]["entity_number"]] 





def refine(blueprint):
	re_index(blueprint)
	electrify(blueprint)

def generate_depot(product):
	iron_ore_depot = "" 
	# iron_ore_depot = ""
	iron_ore_depot_json = convertoToJson(iron_ore_depot)
	copper_ore_depot = ""
	copper_ore_depot_json = convertoToJson(copper_ore_depot)
	for i,v in enumerate(copper_ore_depot_json["blueprint"]["entities"]):
		if v["name"] == "train-stop" and "copper" in v["station"]:
			v["station"] = v["station"].replace("copper ore",product)
			copper_ore_depot_json["blueprint"]["entities"][i]=v
	return copper_ore_depot_json

