def find_nearest(type, coords, map):
	mindist = 10000
	return_entity = None
	for i,v in enumerate(map["blueprint"]["entities"]):
		if v["name"] == type:
			current_dist = (v["position"]["x"] - coords["x"])**2 + (v["position"]["y"] - coords["y"])**2 
			if current_dist < mindist:
				return_entity = v
				current_dist = mindist

	return return_entity
